import anthropic, json, re

client = anthropic.Anthropic()

def find_elements(screenshot_uri: str, task: str) -> list[dict]:
    """Ask the vision model to locate UI elements relevant to a task.

    Returns a list of dicts: {label, type, x, y, width, height, text}
    Coordinates are in the same pixel space as the original screenshot.
    """
    response = client.messages.create(
        model="claude-opus-4-8",
        max_tokens=1024,
        messages=[
            {
                "role": "user",
                "content": [
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": "image/png",
                            "data": screenshot_uri.split(",", 1)[1],  # strip data: prefix
                        },
                    },
                    {
                        "type": "text",
                        "text": (
                            f"Task: {task}\n\n"
                            "List every relevant UI element. "
                            "Respond ONLY with a JSON array. Each element: "
                            '{"label": str, "type": "button|input|link|checkbox|text|image|dropdown", '
                            '"x": int, "y": int, "width": int, "height": int, "text": str}. '
                            "x,y is the top-left corner. "
                            "Include only elements needed for the task."
                        ),
                    },
                ],
            }
        ],
    )
    raw = response.content[0].text
    # Extract JSON array even if model adds prose around it
    m = re.search(r"\[.*\]", raw, re.DOTALL)
    if not m:
        return []
    return json.loads(m.group())

import anthropic, json, re
from typing import TypedDict

client = anthropic.Anthropic()

class ScreenSummary(TypedDict):
    page_type: str      # "login", "dashboard", "checkout", "search-results", ...
    title: str          # visible page/window title
    primary_action: str # main CTA visible (e.g. "Submit", "Sign In", "Buy Now")
    sections: list[str] # major visual regions: ["navbar", "search bar", "result list"]
    error_messages: list[str]  # any visible error or warning text

def describe_screen(screenshot_uri: str) -> ScreenSummary:
    """Produce a high-level summary of the screen state."""
    response = client.messages.create(
        model="claude-opus-4-8",
        max_tokens=512,
        messages=[{
            "role": "user",
            "content": [
                {
                    "type": "image",
                    "source": {
                        "type": "base64",
                        "media_type": "image/png",
                        "data": screenshot_uri.split(",", 1)[1],
                    },
                },
                {
                    "type": "text",
                    "text": (
                        "Describe this screen. Respond with a JSON object matching:\n"
                        "{ page_type, title, primary_action, sections: [str], error_messages: [str] }\n"
                        "JSON only, no prose."
                    ),
                },
            ],
        }],
    )
    m = re.search(r"\{.*\}", response.content[0].text, re.DOTALL)
    if not m:
        return ScreenSummary(page_type="unknown", title="", primary_action="", sections=[], error_messages=[])
    return json.loads(m.group())

import time, hashlib
from PIL import ImageGrab
import io

def wait_for_stable_screen(
    poll_interval: float = 0.5,
    stable_for: float = 1.0,
    timeout: float = 10.0,
) -> None:
    """Block until the screen has not changed for `stable_for` seconds.

    Uses a fast pixel hash to detect changes without storing full images.
    Raises TimeoutError if the screen keeps changing past `timeout`.
    """
    def _screen_hash() -> str:
        buf = io.BytesIO()
        ImageGrab.grab().save(buf, format="PNG")
        return hashlib.md5(buf.getvalue()).hexdigest()

    deadline = time.monotonic() + timeout
    stable_since: float | None = None
    last_hash = _screen_hash()

    while True:
        if time.monotonic() > deadline:
            raise TimeoutError("Screen did not stabilise within the timeout.")
        time.sleep(poll_interval)
        current_hash = _screen_hash()
        if current_hash == last_hash:
            if stable_since is None:
                stable_since = time.monotonic()
            elif time.monotonic() - stable_since >= stable_for:
                return  # screen has been stable long enough
        else:
            last_hash = current_hash
            stable_since = None  # reset stability window

import anthropic, json, re
import pyautogui
from PIL import ImageGrab

client = anthropic.Anthropic()

SYSTEM = """You are a computer-use agent. On each turn you receive:
- A screenshot of the current screen
- The task to complete
- The history of actions taken so far

Respond with a JSON object:
{
  "reasoning": "<what you observe and why>",
  "done": false,
  "action": {
    "type": "click|type|scroll|key|wait",
    "x": int,          // for click
    "y": int,          // for click
    "text": str,       // for type / key
    "dx": int,         // for scroll (pixels)
    "dy": int          // for scroll (pixels)
  }
}
If the task is complete, set done=true and omit action.
"""

def run_agent(task: str, max_steps: int = 20) -> str:
    history: list[dict] = []
    screen_size = ImageGrab.grab().size  # original resolution

    for step in range(max_steps):
        wait_for_stable_screen()
        screenshot_uri = capture_screen()
        summary = describe_screen(screenshot_uri)

        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=512,
            system=SYSTEM,
            messages=[{
                "role": "user",
                "content": [
                    {
                        "type": "image",
                        "source": {"type": "base64", "media_type": "image/png",
                                   "data": screenshot_uri.split(",", 1)[1]},
                    },
                    {
                        "type": "text",
                        "text": json.dumps({
                            "task": task,
                            "page": summary,
                            "history": history[-6:],  # keep context window small
                        }),
                    },
                ],
            }],
        )
        m = re.search(r"\{.*\}", response.content[0].text, re.DOTALL)
        if not m:
            break
        decision = json.loads(m.group())
        if decision.get("done"):
            return f"Task complete after {step + 1} steps."

        action = decision["action"]
        history.append({"step": step, "reasoning": decision["reasoning"], "action": action})

        # Execute the action
        if action["type"] == "click":
            pyautogui.click(action["x"], action["y"])
        elif action["type"] == "type":
            pyautogui.typewrite(action["text"], interval=0.05)
        elif action["type"] == "key":
            pyautogui.press(action["text"])
        elif action["type"] == "scroll":
            pyautogui.scroll(action.get("dy", 0))
        elif action["type"] == "wait":
            import time; time.sleep(2)

    return "Max steps reached without completing task."
